ALTER TABLE CHECKLIST ADD COLUMN DATE_NEW_NEW TIMESTAMP;
UPDATE CHECKLIST SET DATE_NEW_NEW=CAST ( DATE_NEW as TIMESTAMP);
ALTER TABLE CHECKLIST DROP COLUMN DATE_NEW;
RENAME COLUMN CHECKLIST.DATE_NEW_NEW TO DATE_NEW;

ALTER TABLE CHECKLIST ADD COLUMN DATE_EDIT_NEW TIMESTAMP;
UPDATE CHECKLIST SET DATE_EDIT_NEW=CAST ( DATE_EDIT as TIMESTAMP);
ALTER TABLE CHECKLIST DROP COLUMN DATE_EDIT;
RENAME COLUMN CHECKLIST.DATE_EDIT_NEW TO DATE_EDIT;

